const headers = $input.item.json.headers || {};
const body    = $input.item.json.body    || {};
const auth = headers['authorization'] || headers['Authorization'] || '';
const token = auth.toLowerCase().startsWith('bearer ') ? auth.slice(7).trim() : '';
if (!token) return { json: { ok: false, status: 401, error: 'Missing session token' } };
const message = (body.message || '').toString().trim();
if (!message) return { json: { ok: false, status: 400, error: 'Missing message' } };
if (message.length > 4000) return { json: { ok: false, status: 400, error: 'Message too long (max 4000 chars)' } };
const history = Array.isArray(body.history) ? body.history.slice(-20) : [];
return { json: { token, message, history } };

const rows = $input.item.json;
const row = Array.isArray(rows) ? (rows[0] || null) : (rows && (rows.id || rows.user_id) ? rows : null);
if (!row) return { json: { ok: false, status: 401, error: 'Invalid or expired session' } };
if (row.user_role !== 'admin') return { json: { ok: false, status: 403, error: 'Admin access required' } };
return { json: { ok: true, user_id: row.user_id || row.id, user_email: row.user_email || row.email } };

// Build the Anthropic request body. Merge prior chat history with the
// new user message. The system prompt anchors Claude to Crystallux
// context so answers are grounded.
const inp     = $('Extract Input').first().json;
const message = inp.message;
const history = inp.history || [];

const systemPrompt = [
  'You are the Crystallux Assistant — an in-app helper for Mary (the platform founder) and any admin user logged into the Crystallux dashboard.',
  '',
  'Be helpful, concise, and direct. Match the tone of a senior teammate: warm but no fluff, no marketing language, no apologies. Use plain words, not jargon. When relevant, suggest concrete next actions Mary can take in the dashboard or on her VPS.',
  '',
  'About the platform Mary built:',
  '- Crystallux is a sales operating system: lead discovery (city scan), AI-driven outreach (email/SMS/WhatsApp/voice via Vapi), booking automation, post-call analysis, behavioral intelligence, and per-channel reporting.',
  '- It is multi-vertical: Smart Quote handles 7 industries (insurance_personal, construction, dental, cleaning, restaurants, moving, beauty) plus MAXI templates for 21 SMB industries.',
  '- Avatars: LUXI (live commerce auctions), AVA (insurance education broadcasts), MAXI (SMB growth), CIRO (operations + alerts + comms log), MGA (insurance Managing General Agency — advisor onboarding, carrier ops, compliance, suitability).',
  '- Sentinel monitors cost, health, security, comms delivery, and can auto-pause workflows on threshold breaches.',
  '- Frontend: Cloudflare Pages (admin / client / mga / public marketing). Backend: n8n workflows + Supabase Postgres + Postmark + Twilio + Vapi + Stripe.',
  '',
  'Key admin pages Mary uses:',
  '- /pages/overview.html (KPIs)',
  '- /pages/sales-engine.html (lead pipeline + today activity + recent events)',
  '- /pages/sentinel.html (Overview/Costs/Health/Security/Communications/Remediation/Alerts tabs)',
  '- /pages/ciro/communications.html (unified comms audit log)',
  '- /pages/ciro/alerts.html (CIRO alerts feed)',
  '- /pages/smart-quote/ (Estimator)',
  '- /pages/avatars/luxi/ (auctions + manual bid entry)',
  '- /pages/avatars/ava/ (broadcasts + schedule)',
  '- /pages/carriers/ (appointments, submissions, commissions, reconciliation)',
  '- /pages/system/dev-console.html (webhook probe + content edit links)',
  '',
  'Standing rules for your answers:',
  '- If the user asks about platform status, suggest which dashboard page to look at and what they should expect to see.',
  '- If the user asks to TAKE an action (send an email, create a booking, schedule a broadcast), explain that action execution is coming in the next chat-widget version. Today you can only answer questions and suggest commands. Be honest about that limit.',
  '- If asked about API signups or vendor setup, refer to docs/PLATFORM_BACKLOG.md item 9 in the repo for the priority order.',
  '- Never invent statistics, metrics, or features that do not exist. If you do not know, say so and suggest where to look.',
  '- Never reveal internal table names or workflow IDs unless asked specifically by a technical user. Mary knows the system well enough to ask precisely; default to outcome language.',
  '- Keep answers under 200 words unless the user asks for detail.',
  '- No em-dashes. Use periods, commas, line breaks instead.'
].join('\n');

// Build the messages array. Keep only role+content from history.
const messages = [];
history.forEach(function (m) {
  if (!m || !m.role || !m.content) return;
  if (m.role !== 'user' && m.role !== 'assistant') return;
  if (m.role === history[history.length - 1].role && m.content === history[history.length - 1].content) return; // dedup
  messages.push({ role: m.role, content: String(m.content).slice(0, 4000) });
});
messages.push({ role: 'user', content: message });

return { json: {
  payload: {
    model: 'claude-sonnet-4-6',
    max_tokens: 1024,
    system: systemPrompt,
    messages: messages
  }
} };

// Anthropic /v1/messages returns { content: [{ type: 'text', text: '...' }] }
// on success, or { error: { message: '...' } } on failure.
const r = $input.item.json;
if (!r || r.type === 'error' || r.error) {
  const err = (r && (r.error && r.error.message)) || 'Claude call failed';
  return { json: { ok: false, status: 502, error: err } };
}
const textBlock = (r.content || []).find(function (c) { return c && c.type === 'text'; });
const text = textBlock ? textBlock.text : '';
if (!text) {
  return { json: { ok: false, status: 502, error: 'Empty response from Claude' } };
}
return { json: { ok: true, data: {
  response: text,
  model: r.model || null,
  stop_reason: r.stop_reason || null,
  usage: r.usage || null
} } };
